import{_ as e,o as t,c as a,a2 as l}from"./chunks/framework.DnrXFDHb.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/市場情緒/市場情緒_20260601.md","filePath":"Deep32Q知識庫/市場情緒/市場情緒_20260601.md"}'),i={name:"Deep32Q知識庫/市場情緒/市場情緒_20260601.md"};function o(n,r,s,g,h,u){return t(),a("div",null,[...r[0]||(r[0]=[l('<p>📊 市場情緒日報 — 2026年6月1日（週一）</p><blockquote><p><strong>查詢時間</strong>：TST 06:02 (2026-06-01 06:02 = 2026-05-31 22:02 UTC) <strong>敘事錨點</strong>：🔥 Trump 拒絕伊朗 MoU 並送出修訂版（第3輪修改）+ COMPUTEX 6/2 開幕 + 黃仁勳今日 GTC Taipei 演講 + 美股連漲9週創紀錄</p></blockquote><hr><h2 id="🔑-今日最大事件-前3點深度敘事" tabindex="-1">🔑 今日最大事件（前3點深度敘事） <a class="header-anchor" href="#🔑-今日最大事件-前3點深度敘事" aria-label="Permalink to &quot;🔑 今日最大事件（前3點深度敘事）&quot;">​</a></h2><h3 id="_1-🇺🇸🇮🇷-trump-拒絕伊朗停火-mou-送出第3輪修訂版-—-僵局升級" tabindex="-1">1. 🇺🇸🇮🇷 Trump 拒絕伊朗停火 MoU，送出第3輪修訂版 — 僵局升級 <a class="header-anchor" href="#_1-🇺🇸🇮🇷-trump-拒絕伊朗停火-mou-送出第3輪修訂版-—-僵局升級" aria-label="Permalink to &quot;1. 🇺🇸🇮🇷 Trump 拒絕伊朗停火 MoU，送出第3輪修訂版 — 僵局升級&quot;">​</a></h3><ul><li><strong>最新動態（5/31-6/1）</strong>： <ul><li><strong>Trump 對伊朗 MoU 做出第3輪修改</strong>，重點修訂荷莫茲海峽重新開放條款 + 高濃縮鈾移除條件</li><li>修訂版已透過巴基斯坦調停人送回德黑蘭，<strong>伊朗尚未回覆</strong></li><li>Trump 在 Lara Trump 專訪中表示：「我不急著達成協議」（&quot;no hurry&quot;），因為「沒有任何協議是夠好的」</li><li>Trump 同時表示伊朗已同意「不發展核武」，但<strong>核設施檢查與鈾移除問題仍未解決</strong></li><li><strong>巴基斯坦調停</strong>：第三方調停機制持續運作，但雙方立場差距仍大</li><li><strong>以色列-真主黨升級</strong>：以軍佔領黎巴嫩 Beaufort 城堡（25年來最深入黎巴嫩的軍事行動），Netanyahu 稱此為「戲劇性轉折」</li><li><strong>科威特基地遇襲</strong>：4名美軍+3名承包商在伊朗彈道導彈襲擊中受輕傷，24小時內返回崗位</li></ul></li><li><strong>影響鏈</strong>： <ul><li>第3輪修改 → 伊朗回覆期限不確定 → 封鎖持續 → 油價支撐 → 化肥成本壓力延續</li><li>以色列-真主黨升級 → 中東風險溢價回升 → 避險需求增加 → 金價支撐</li><li>Trump「不急」→ 市場不確定性延長 → 高波動環境持續</li></ul></li><li><strong>關鍵節點</strong>：伊朗回覆時間、Trump 最終決定、以色列-黎巴嫩地面行動進展</li><li>來源：<a href="https://www.cbsnews.com/live-updates/iran-war-us-trump-vance-ceasefire-strait-of-hormuz-deal-close" target="_blank" rel="noreferrer">CBS News</a> · <a href="https://www.chosun.com/english/world-en/2026/06/01/5WW2C5G6OFFM5C4B34WCCHQGTE" target="_blank" rel="noreferrer">Chosun</a> · <a href="https://www.hindustantimes.com/world-news/us-iran-war-news-live-updates-ceasefire-peace-deal-donald-trump-strikes-strait-of-hormuz-netanyahu-israel-lebanon-latest-101780187912874.html" target="_blank" rel="noreferrer">Hindustan Times</a> （T: 06:02 TST）</li></ul><h3 id="_2-💻-computex-今日倒數-黃仁勳-gtc-taipei-演講在即" tabindex="-1">2. 💻 COMPUTEX 今日倒數 + 黃仁勳 GTC Taipei 演講在即 <a class="header-anchor" href="#_2-💻-computex-今日倒數-黃仁勳-gtc-taipei-演講在即" aria-label="Permalink to &quot;2. 💻 COMPUTEX 今日倒數 + 黃仁勳 GTC Taipei 演講在即&quot;">​</a></h3><ul><li><strong>COMPUTEX 2026</strong>：6/2-5 台北南港展覽館，主題「AI Together」，1,500 家參展商</li><li><strong>黃仁勳 GTC Taipei</strong>：<strong>6/1（今日）</strong> 台北流行音樂中心，聚焦： <ul><li><strong>Vera Rubin 架構</strong>：Vera CPU + Rubin GPU，機櫃級超級電腦</li><li><strong>NVIDIA 光子投資 $40 億</strong>：Coherent + Lumentum 各 $20 億，取得雷射元件優先使用權</li><li><strong>Spectrum-X Photonics</strong>：409.6 Tb/s，2026 下半年上市</li><li><strong>「A new era of PC」神秘貼文</strong>：NVIDIA 5/29 在 X 發布，微軟+Arm 同步轉發，暗示 PC 新時代</li></ul></li><li><strong>台灣光通訊族群</strong>：5/25 波若威、光聖、聯亞、前鼎 4 檔漲停</li><li><strong>大摩 COMPUTEX 報告</strong>：點名台積電、聯電、京元電、日月光、鴻海等 9 檔</li><li>來源：<a href="https://www.nvidia.com/en-tw/gtc/taipei/computex/" target="_blank" rel="noreferrer">NVIDIA</a> · <a href="https://news.cnyes.com/news/id/6469850" target="_blank" rel="noreferrer">鉅亨網</a> · <a href="https://baxtel.com/events/nvidia-gtc-taipei-2026" target="_blank" rel="noreferrer">Baxtel</a> （T: 06:02 TST）</li></ul><h3 id="_3-🇺🇸-美股連漲9週創紀錄-s-p-500-dow-歷史新高-ai-驅動牛市" tabindex="-1">3. 🇺🇸 美股連漲9週創紀錄：S&amp;P 500 + Dow 歷史新高，AI 驅動牛市 <a class="header-anchor" href="#_3-🇺🇸-美股連漲9週創紀錄-s-p-500-dow-歷史新高-ai-驅動牛市" aria-label="Permalink to &quot;3. 🇺🇸 美股連漲9週創紀錄：S&amp;P 500 + Dow 歷史新高，AI 驅動牛市&quot;">​</a></h3><ul><li><strong>5/29 收盤</strong>： <ul><li>S&amp;P 500：7,580.06（+0.22%）— <strong>連續第9週上漲</strong>，2023年以來最長</li><li>道瓊：51,032.46（+0.72%），首度站上 51,000</li><li>Nasdaq：26,972.62（+0.20%）</li></ul></li><li><strong>亮點</strong>： <ul><li>Dell +32.8%（AI 需求強勁，上調財測）</li><li>Oracle +10.8%（財報亮眼）</li><li>Micron 突破 $1 兆市值（5/26）</li><li>Dollar Tree +11%（財報超預期）</li></ul></li><li><strong>警告</strong>： <ul><li>Buffett 指標 ~231% 歷史新高</li><li>S&amp;P 500 Q1 估計盈餘成長 28.4%（歷史高成長常出現在牛市末期）</li></ul></li><li>來源：<a href="https://www.cnbc.com/2026/05/27/stock-market-today-live-updates.html" target="_blank" rel="noreferrer">CNBC</a> · <a href="https://www.thestreet.com/stock-market-today/stock-market-today-dow-jones-sp-500-nasdaq-updates-may-29-2026" target="_blank" rel="noreferrer">TheStreet</a> （T: 06:02 TST）</li></ul><hr><h2 id="📋-次要事件-第4-8點" tabindex="-1">📋 次要事件（第4-8點） <a class="header-anchor" href="#📋-次要事件-第4-8點" aria-label="Permalink to &quot;📋 次要事件（第4-8點）&quot;">​</a></h2><h3 id="_4-🥇-黃金穩站-4-535-4-540-美伊僵局-以色列升級支撐避險" tabindex="-1">4. 🥇 黃金穩站 $4,535-4,540：美伊僵局+以色列升級支撐避險 <a class="header-anchor" href="#_4-🥇-黃金穩站-4-535-4-540-美伊僵局-以色列升級支撐避險" aria-label="Permalink to &quot;4. 🥇 黃金穩站 $4,535-4,540：美伊僵局+以色列升級支撐避險&quot;">​</a></h3><ul><li><strong>XAU/USD spot</strong>：~$4,535-$4,540/oz（5/31）</li><li><strong>COMEX 期貨</strong>：~$4,526/oz（5/29 收盤）</li><li><strong>交叉驗證</strong>：Spot $4,540 vs Futures $4,526，價差 ~$14，正常範圍 ✅</li><li><strong>驅動</strong>：Trump 拒絕 MoU → 以色列佔領 Beaufort 城堡 → 中東風險回升 → 避險需求</li><li><strong>Kitco 報價</strong>：Bid $4,538.30 / Ask $4,540.30，日漲 +$43.40（+0.97%）</li><li>來源：<a href="https://www.kitco.com/" target="_blank" rel="noreferrer">Kitco</a> · <a href="https://tradingeconomics.com/commodity/gold" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://sundayguardianlive.com/business/gold-rate-today-31-may-2026-live-updates-us-gold-rates-edges-lower-to-4535-amid-us-iran-war-domestic-rates-above-157-lakh10g-check-city-wise-price-of-24k-22k-18k-199093/" target="_blank" rel="noreferrer">SundayGuardianLive</a> （T: 06:02 TST）</li></ul><h3 id="_5-⛽-油價-5-月暴跌-16-17-wti-87-76-三角收斂測底部" tabindex="-1">5. ⛽ 油價 5 月暴跌 16-17%：WTI $87.76，三角收斂測底部 <a class="header-anchor" href="#_5-⛽-油價-5-月暴跌-16-17-wti-87-76-三角收斂測底部" aria-label="Permalink to &quot;5. ⛽ 油價 5 月暴跌 16-17%：WTI $87.76，三角收斂測底部&quot;">​</a></h3><ul><li><strong>WTI</strong>：$87.76/bbl（5/29 收盤，月跌 -16.2%）</li><li><strong>技術面</strong>：測試多月三角收斂底部支撐 $87.75，RSI 超賣 35-40</li><li><strong>Brent</strong>：~$91/bbl 區間</li><li><strong>5月走勢</strong>：3月高點 $120+ → 5月底 $87-91，累計回落 ~25-27%</li><li><strong>驅動</strong>：美伊停火希望壓制溢價 → 但封鎖持續 + 以色列升級 → 下行有支撐</li><li>來源：<a href="https://www.marketwatch.com/investing/future/clm26" target="_blank" rel="noreferrer">MarketWatch</a> · <a href="https://www.fxleaders.com/news/2026/05/31/wti-crude-price-weekly-outlook-will-triangle-support-spark-a-move-back-over-94" target="_blank" rel="noreferrer">FXLeaders</a> （T: 06:02 TST）</li></ul><h3 id="_6-💵-美元指數-98-93-98-97-穩定-kevin-warsh-新官上任" tabindex="-1">6. 💵 美元指數 98.93-98.97 穩定：Kevin Warsh 新官上任 <a class="header-anchor" href="#_6-💵-美元指數-98-93-98-97-穩定-kevin-warsh-新官上任" aria-label="Permalink to &quot;6. 💵 美元指數 98.93-98.97 穩定：Kevin Warsh 新官上任&quot;">​</a></h3><ul><li><strong>DXY</strong>：~98.93-98.97（5/29-31）</li><li><strong>新任 Fed 主席 Kevin Warsh</strong>：首週設定基調，市場關注其政策方向</li><li><strong>連鎖反應</strong>：美元穩定 → 金價支撐 → 亞幣承壓（KRW 157、JPY 159）</li><li>來源：<a href="https://www.fxleaders.com/news/2026/05/31/inflation-dollar-and-rates-kevin-warshs-first-week-sets-the-tone/" target="_blank" rel="noreferrer">FXLeaders</a> · <a href="https://www.barchart.com/futures/quotes/DXM26" target="_blank" rel="noreferrer">Barchart</a> （T: 06:02 TST）</li></ul><h3 id="_7-🇹🇼-台股-44-732-歷史新高-5月狂飆-5-806-點-computex-催動" tabindex="-1">7. 🇹🇼 台股 44,732 歷史新高：5月狂飆 5,806 點，COMPUTEX 催動 <a class="header-anchor" href="#_7-🇹🇼-台股-44-732-歷史新高-5月狂飆-5-806-點-computex-催動" aria-label="Permalink to &quot;7. 🇹🇼 台股 44,732 歷史新高：5月狂飆 5,806 點，COMPUTEX 催動&quot;">​</a></h3><ul><li><strong>TAIEX</strong>：44,732.94（5/29 收盤，歷史新高）</li><li><strong>5月漲幅</strong>：+5,806 點（+14.9%），<strong>台股史上最強5月</strong></li><li><strong>外資月買超</strong>：2,360.2 億元</li><li><strong>台積電</strong>：盤後鉅額交易出現 2,442 元新高價</li><li><strong>今日（6/1）</strong>：正常開盤，COMPUTEX 相關活動啟動</li><li>來源：<a href="https://news.cnyes.com/news/id/6469850" target="_blank" rel="noreferrer">鉅亨網</a> · <a href="https://news.cnyes.com/news/id/6477728" target="_blank" rel="noreferrer">FTNN</a> （T: 06:02 TST）</li></ul><h3 id="_8-🫘-黃豆小幅回落-cbot-7月-1-186-75-¢-bu-種植進度超前" tabindex="-1">8. 🫘 黃豆小幅回落：CBOT 7月 1,186.75 ¢/bu，種植進度超前 <a class="header-anchor" href="#_8-🫘-黃豆小幅回落-cbot-7月-1-186-75-¢-bu-種植進度超前" aria-label="Permalink to &quot;8. 🫘 黃豆小幅回落：CBOT 7月 1,186.75 ¢/bu，種植進度超前&quot;">​</a></h3><ul><li><strong>CBOT 7月黃豆（ZSN26）</strong>：1,186.75 ¢/bu（5/29 收盤，-0.65%）</li><li><strong>11月新作（SX26）</strong>：1,196 ¢ 開盤，日內 1,186-1,199</li><li><strong>USDA WASDE</strong>：2026/27 年度均價預測 $11.40/bu（高於 2025/26 的 $10.40）</li><li><strong>現貨</strong>：Iowa 均價 $11.23/bu，Minneapolis 1,134.75-1,138.75 ¢/bu</li><li>來源：<a href="https://tradingeconomics.com/commodity/soybeans" target="_blank" rel="noreferrer">TradingEconomics</a> · <a href="https://www.marketwatch.com/investing/future/sx26" target="_blank" rel="noreferrer">MarketWatch</a> · <a href="https://www.ers.usda.gov/topics/crops/soybeans-and-oil-crops/market-outlook" target="_blank" rel="noreferrer">USDA</a> （T: 06:02 TST）</li></ul><hr><h2 id="🔮-前瞻預警-第9-10點" tabindex="-1">🔮 前瞻預警（第9-10點） <a class="header-anchor" href="#🔮-前瞻預警-第9-10點" aria-label="Permalink to &quot;🔮 前瞻預警（第9-10點）&quot;">​</a></h2><h3 id="_9-📅-本週焦點-黃仁勳今日演講-非農就業-computex-開展" tabindex="-1">9. 📅 本週焦點：黃仁勳今日演講 + 非農就業 + COMPUTEX 開展 <a class="header-anchor" href="#_9-📅-本週焦點-黃仁勳今日演講-非農就業-computex-開展" aria-label="Permalink to &quot;9. 📅 本週焦點：黃仁勳今日演講 + 非農就業 + COMPUTEX 開展&quot;">​</a></h3><ul><li><strong>6/1（今日）</strong>：黃仁勳 GTC Taipei 演講（台北流行音樂中心）</li><li><strong>6/2-5</strong>：COMPUTEX 2026 台北南港展覽館</li><li><strong>6/6（週五）</strong>：美國非農就業報告（NFP）— 市場高度關注</li><li><strong>6/2</strong>：USDA Crop Progress 報告（黃豆播種進度更新）</li><li><strong>以色列-黎巴嫩</strong>：Beaufort 城堡佔領後，地面行動可能擴大</li><li>來源：<a href="https://www.nvidia.com/en-tw/gtc/taipei/computex/" target="_blank" rel="noreferrer">NVIDIA</a> · <a href="https://www.fxleaders.com/news/2026/05/31/gold-price-forecast-xau-heads-for-5k-on-us-iran-deal-hopes-and-soft-us-pce-awaiting-nfp/" target="_blank" rel="noreferrer">FXLeaders</a> （T: 06:02 TST）</li></ul><h3 id="_10-🌍-地緣風險全景-美伊僵局-以色列擴大黎巴嫩行動-中國農產品承諾" tabindex="-1">10. 🌍 地緣風險全景：美伊僵局 + 以色列擴大黎巴嫩行動 + 中國農產品承諾 <a class="header-anchor" href="#_10-🌍-地緣風險全景-美伊僵局-以色列擴大黎巴嫩行動-中國農產品承諾" aria-label="Permalink to &quot;10. 🌍 地緣風險全景：美伊僵局 + 以色列擴大黎巴嫩行動 + 中國農產品承諾&quot;">​</a></h3><ul><li><strong>美伊</strong>：第3輪修改 → 伊朗未回覆 → 封鎖持續 → 市場不確定性延長</li><li><strong>以色列-真主黨</strong>：Beaufort 城堡陷落 → 法國要求安理會緊急會議 → 衝突升級</li><li><strong>中美貿易</strong>：中國承諾 2026-28 年每年 $170 億農產品（含黃豆 2,500 萬噸/年），但北京未即時確認</li><li><strong>Buffett 指標</strong>：231% 歷史新高 → 牛市末期警告持續</li><li><strong>風險平衡</strong>：AI 驅動牛市 vs 地緣不確定性 vs 通膨/利率 → 高波動環境</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li>CBS News (2026-05/31): Trump 第3輪修改伊朗 MoU，重點在荷莫茲+高濃縮鈾</li><li>Chosun (2026-06-01): Trump 拒絕伊朗停火 MoU 送出修訂版</li><li>Hindustan Times (2026-06/01): 伊朗將提交新修正案</li><li>NVIDIA (2026): GTC Taipei 6/1 演講，Vera Rubin 架構</li><li>Baxtel (2026): GTC Taipei 6/1-4 日程</li><li>CNBC (2026-05-27): S&amp;P 500 + Nasdaq 創紀錄，9週連漲</li><li>TheStreet (2026-05-29): S&amp;P 500 第9週連漲</li><li>Kitco (2026-05-31): XAU/USD $4,538.30/$4,540.30</li><li>TradingEconomics (2026-05-29): COMEX Gold $4,526, Soybeans 1,186.75</li><li>MarketWatch (2026-05-29): WTI $87.76, Soybean Nov $1,196</li><li>FXLeaders (2026-05-31): WTI 三角收斂 $87.75 支撐</li><li>FXLeaders (2026-05-31): Kevin Warsh 新官上任，金價瞄準 $5K</li><li>鉅亨網 (2026-05-25): 光通訊4檔漲停</li><li>USDA (2026): WASDE 2026/27 黃豆均價 $11.40/bu</li><li>Barchart (2026-05-29): DXY 98.969</li></ol>',31)])])}const m=e(i,[["render",o]]);export{d as __pageData,m as default};
